const data = $input.first().json;

const industry = (data.Industry || '').trim();
const country = (data.Country || '').trim();
const state = (data.State || '').trim();

// Global-friendly: state is optional
const location_str = state ? `${state}, ${country}` : `${country}`;

const context = state
  ? `${industry} in ${state}, ${country}`
  : `${industry} in ${country}`;

return [{
  json: {
    context,
    industry,
    country,
    state: state || null,
    location_str,
    num_search_terms: Number(data.num_search_terms ?? 2),
    top_results: Number(data.top_results ?? 10),
  }
}];

const results = [];
const seen = new Set();

for (const [index, item] of $input.all().entries()) {
  const place = item.json;

  if (!place.title) continue;
  if (!place.address) continue;
  if (place.permanentlyClosed === true) continue;
  if (!place.website) continue;
  if (!place.phoneNumber) continue;
  if ((place.rating ?? 0) < 4.0) continue;
  if ((place.ratingCount ?? 0) < 10) continue;

  const uniqueId = place.placeId || `${place.title}|${place.address}`;
  if (seen.has(uniqueId)) continue;
  seen.add(uniqueId);

  results.push({
    json: {
      business_name: place.title,
      name: place.title,
      address: place.address,
      phone: place.phoneNumber,
      website: place.website,
      rating: place.rating ?? null,
      reviews: place.ratingCount ?? null,
      category: place.type ?? null,
      placeId: place.placeId ?? null,
    },
    pairedItem: {
      item: index,
    },
  });
}

return results;

