const payload = Array.isArray($json) ? $json[0] : $json;
const organic = payload.organic || [];

const rawWebsite = ($node["Loop Over Items"].json.website || "").trim();

const domain = rawWebsite
  .replace(/^https?:\/\//i, "")
  .replace(/^www\./i, "")
  .split("?")[0]
  .split("#")[0]
  .split("/")[0]
  .toLowerCase();

const isLikelyContact = (url = "") => {
  const x = url.toLowerCase();
  return (
    x.includes("/contact") ||
    x.includes("contact-us") ||
    x.includes("get-in-touch") ||
    x.includes("/support") ||
    x.includes("/help") ||
    x.includes("/book") ||
    x.includes("/booking") ||
    x.includes("/schedule") ||
    x.includes("appointment") ||
    x.includes("request-service") ||
    x.includes("service-request")
  );
};

let contact_url = null;
let trustpilot_url = null;

for (const r of organic) {
  const link = (r.link || "").trim();
  if (!link) continue;

  if (!contact_url && link.toLowerCase().includes(domain) && isLikelyContact(link)) {
    contact_url = link;
  }

  if (!trustpilot_url && link.toLowerCase().includes("trustpilot.com/review/")) {
    trustpilot_url = link;
  }
}

const canonical_url = domain ? `https://www.${domain}` : null;

return [
  {
    json: {
      ...$json,
      domain,
      canonical_url,
      contact_url,
      trustpilot_url,
      organic_count: organic.length,
    },
    pairedItem: {
      item: 0,
    },
  },
];

const html = String($json.data || "");

// ============================================================
// NEW: Extract all emails from full raw HTML before anything
// is sliced, cleaned or deleted. We cap at 500k characters
// to prevent the runner timing out on very large pages.
// ============================================================
const extractEmailsFromText = (text) => {
  const raw = String(text || "");
  const found = [];
  const plain = raw.match(/[a-zA-Z0-9._%+-]+@[a-zA-Z0-9.-]+\.[a-z]{2,}/g) || [];
  found.push(...plain);
  return [...new Set(found.map(e => e.toLowerCase().trim()))].filter(e => e.includes("@"));
};

// NEW: Cap HTML size before scanning to avoid runner timeout
const homepage_emails_raw = extractEmailsFromText(html.slice(0, 500000));
// ============================================================

// Extract only the <body> if available
const bodyMatch = html.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
const source = bodyMatch ? bodyMatch[1] : html;

// Extract href links before stripping tags
const hrefs = [...source.matchAll(/href=["']([^"'#]+)["']/gi)]
  .map(m => String(m[1] || "").trim())
  .filter(Boolean);

// Extract + normalize + deduplicate mailto links
const homepage_mailtos = [...new Set(
  hrefs
    .filter(h => /^mailto:/i.test(h))
    .map(h =>
      h
        .replace(/^mailto:/i, "")
        .split("?")[0]
        .trim()
        .toLowerCase()
    )
    .filter(Boolean)
)];

// Remove noisy blocks
const cleaned = source
  .replace(/<script[\s\S]*?<\/script>/gi, " ")
  .replace(/<style[\s\S]*?<\/style>/gi, " ")
  .replace(/<noscript[\s\S]*?<\/noscript>/gi, " ")
  .replace(/\s+/g, " ")
  .trim();

// Create top and bottom chunks
const homepage_text_top = cleaned.slice(0, 12000);
const homepage_text_bottom = cleaned.slice(-12000);

// Remove bulky/raw input fields
const { data, website_html, ...rest } = $json;

return [
  {
    json: {
      ...rest,
      homepage_text_top,
      homepage_text_bottom,
      homepage_links: hrefs,
      homepage_mailtos,
      homepage_emails_raw, // NEW: full raw HTML email scan added to output
    },
    pairedItem: {
      item: 0,
    },
  },
];

const normalizeEmail = (e) =>
  String(e || "")
    .toLowerCase()
    .trim()
    .replace(/^mailto:/i, "")
    .split("?")[0]
    .replace(/\[at\]|\(at\)|\sat\s/gi, "@")
    .replace(/\[dot\]|\(dot\)|\sdot\s/gi, ".")
    .replace(/\s+/g, "");

const extractEmailsFromText = (text) => {
  const raw = String(text || "");
  const found = [];

  const plain =
    raw.match(/[a-zA-Z0-9._%+-]+@[a-zA-Z0-9.-]+\.[a-z]{2,}/g) || [];
  found.push(...plain);

  const obfuscated =
    raw.match(
      /[a-zA-Z0-9._%+-]+\s*(?:@|\[at\]|\(at\)|\sat\s)\s*[a-zA-Z0-9.-]+\s*(?:\.|\[dot\]|\(dot\)|\sdot\s)\s*[a-z]{2,}/gi
    ) || [];
  found.push(...obfuscated);

  return found.map(normalizeEmail).filter((e) => e.includes("@"));
};

const domain = String($json.domain || "").toLowerCase();
const candidates = [];

const addCandidate = (email, source, score = 0) => {
  const normalized = normalizeEmail(email);
  if (!normalized || !normalized.includes("@")) return;
  candidates.push({ email: normalized, source, score });
};

// ============================================================
// NEW: Raw HTML email sources added first — these catch emails
// that sit in the middle of the page and are missed by the
// top/bottom 12k text chunks. Scored just below explicit
// mailto links but above all text-parsed sources.
// ============================================================
for (const e of ($json.contact_emails_raw || [])) {
  addCandidate(e, "contact_raw", 108);
}
for (const e of ($json.homepage_emails_raw || [])) {
  addCandidate(e, "homepage_raw", 98);
}
// ============================================================

// Explicit mailto links (highest confidence)
for (const e of ($json.contact_mailtos || [])) {
  addCandidate(e, "contact_mailto", 110);
}
for (const e of ($json.homepage_mailtos || [])) {
  addCandidate(e, "homepage_mailto", 100);
}

// Footer/bottom first, then top
for (const e of extractEmailsFromText($json.contact_text_bottom)) {
  addCandidate(e, "contact_bottom", 90);
}
for (const e of extractEmailsFromText($json.homepage_text_bottom)) {
  addCandidate(e, "homepage_bottom", 80);
}
for (const e of extractEmailsFromText($json.contact_text_top)) {
  addCandidate(e, "contact_top", 70);
}
for (const e of extractEmailsFromText($json.homepage_text_top)) {
  addCandidate(e, "homepage_top", 60);
}

// ---- SCORING ----
for (const c of candidates) {
  const emailDomain = c.email.split("@")[1] || "";

  const matchesBusinessDomain =
    domain &&
    (emailDomain === domain || emailDomain.endsWith("." + domain));

  if (matchesBusinessDomain) {
    // Always boost business domain emails
    c.score += 40;
  }
  // ============================================================
  // CHANGED: Removed the -35 non-domain penalty and the -10
  // Gmail/Yahoo/Outlook penalty. Many small businesses use Gmail
  // as their primary contact email. Penalizing it caused valid
  // emails to score so low they were dropped and returned null.
  // Business domain emails still win via the +40 boost above.
  // ============================================================

  // Only penalize noreply — these are never valid contact emails
  if (/noreply|no-reply|donotreply/i.test(c.email)) {
    c.score -= 50;
  }
}

// Deduplicate by best score
const bestByEmail = new Map();
for (const c of candidates) {
  const existing = bestByEmail.get(c.email);
  if (!existing || c.score > existing.score) {
    bestByEmail.set(c.email, c);
  }
}

const ranked = [...bestByEmail.values()].sort((a, b) => b.score - a.score);

// Filter: prefer business domain emails if any exist, else use all
const domainMatched = ranked.filter((c) => {
  const emailDomain = c.email.split("@")[1] || "";
  return domain && (emailDomain === domain || emailDomain.endsWith("." + domain));
});

const finalRanked = domainMatched.length ? domainMatched : ranked;

// ============================================================
// CHANGED: const → let so the fallback scan below can
// reassign these if no email was found from any source above
// ============================================================
let email = finalRanked.length ? finalRanked[0].email : null;
let email_source = finalRanked.length ? finalRanked[0].source : null;
const email_candidates = ranked.map((c) => c.email).slice(0, 5);

// ============================================================
// NEW: Last-resort fallback — if email is still null after all
// sources above, scan every string field in the item for any
// email pattern. Covers edge cases where data lands in
// unexpected fields.
// ============================================================
if (!email) {
  const everything = Object.values($json)
    .filter((v) => typeof v === "string")
    .join("\n");

  const fallbackEmails = extractEmailsFromText(everything);

  if (fallbackEmails.length) {
    email = fallbackEmails[0];
    email_source = "fallback_scan";
  }
}
// ============================================================

// ---- PHONE ----
let phone = $json.phone || null;

const phoneSearch =
  `${$json.contact_text_top || ""}\n` +
  `${$json.contact_text_bottom || ""}\n` +
  `${$json.homepage_text_top || ""}\n` +
  `${$json.homepage_text_bottom || ""}`;

if (!phone) {
  const telMatch = phoneSearch.match(/tel:\+?[0-9().\-\s]{7,}/i);
  if (telMatch) {
    phone = telMatch[0].replace(/^tel:/i, "").trim();
  } else {
    const phoneMatch = phoneSearch.match(
      /(?:\+?1[\s.-]?)?(?:\(?\d{3}\)?[\s.-]?)\d{3}[\s.-]?\d{4}/
    );
    if (phoneMatch) {
      phone = phoneMatch[0].trim();
    }
  }
}

// ---- COMBINED TEXT FOR SIGNALS ----
const combined =
  `${$json.homepage_text_top || ""}\n` +
  `${$json.homepage_text_bottom || ""}\n` +
  `${$json.contact_text_top || ""}\n` +
  `${$json.contact_text_bottom || ""}`;

// ---- SIGNAL DETECTION ----
const hasAny = (patterns, haystack) => patterns.some((p) => p.test(haystack));

const chatSignals = [
  /intercom/i, /drift/i, /tawk\.to/i, /crisp\.chat/i,
  /zendesk/i, /livechat/i, /chat widget/i, /live chat/i,
];

const schedulerSignals = [
  /calendly/i, /acuityscheduling/i, /setmore/i, /youcanbook\.me/i,
  /simplybook/i, /squareup\.com\/appointments/i, /schedule-a-service/i,
  /schedule service/i, /book now/i, /request appointment/i,
];

const instantQuoteSignals = [
  /instant quote/i, /get a quote/i, /request a quote/i,
  /free estimate/i, /estimate/i,
];

const callNowSignals = [
  /call now/i, /tel:/i,
];

const formSignals = [
  /<form\b/i, /contact form/i, /name=["']email["']/i,
];

const crmSignals = [
  /servicetitan/i, /housecallpro/i, /jobber/i,
  /servicefusion/i, /fieldedge/i,
];

const has_chat_widget = hasAny(chatSignals, combined);
const has_scheduler = hasAny(schedulerSignals, combined);
const has_instant_quote = hasAny(instantQuoteSignals, combined);
const has_call_now_cta = hasAny(callNowSignals, combined);
const has_form = hasAny(formSignals, combined);
const crm_detected = crmSignals.some((p) => p.test(combined));

return {
  json: {
    ...$json,
    email,
    email_source,
    email_candidates,
    crm_detected,
    phone,
    has_chat_widget,
    has_scheduler,
    has_instant_quote,
    has_call_now_cta,
    has_form,
  },
  pairedItem: {
    item: 0,
  },
};

const {
  has_chat_widget,
  has_scheduler,
  has_instant_quote,
  has_call_now_cta,
  has_form,
  email,
  phone,
  contact_url,
} = $json;

let score = 0;
const gaps = [];

if (has_call_now_cta) score += 2;
else gaps.push("No clear Call-Now CTA");

if (has_form) score += 3;
else gaps.push("No contact form");

if (has_chat_widget) score += 3;
else gaps.push("No chat widget");

if (has_scheduler) score += 4;
else gaps.push("No booking/scheduler");

if (has_instant_quote) score += 2;
else gaps.push("No instant quote/estimate");

if (email) score += 1;
else gaps.push("No email visible");

if (phone) score += 1;
else gaps.push("No phone detected");

if (score > 10) score = 10;

const pain_point_summary =
  score >= 8
    ? "Strong speed-to-lead setup; only minor improvements needed."
    : score >= 5
      ? "Decent speed-to-lead, but missing 1–2 key instant-response channels."
      : "Slow speed-to-lead risk: missing key response channels and friction is likely causing lost leads.";

const evidence = [
  has_call_now_cta ? "call-now:yes" : "call-now:no",
  has_form ? "form:yes" : "form:no",
  has_chat_widget ? "chat:yes" : "chat:no",
  has_scheduler ? "scheduler:yes" : "scheduler:no",
  has_instant_quote ? "quote:yes" : "quote:no",
  email ? `email:${email}` : "email:none",
  phone ? `phone:${phone}` : "phone:none",
  contact_url ? `contact_url:${contact_url}` : "contact_url:none",
].join(" | ");

return [
  {
    json: {
      ...$json,
      speed_to_lead_score: score,
      speed_to_lead_gaps: gaps.join("; "),
      pain_point_summary,
      evidence,
    },
    pairedItem: {
      item: 0,
    },
  },
];

const html = String($json.data || "");

// ============================================================
// NEW: Extract all emails from full raw HTML before anything
// is sliced, cleaned or deleted. This catches emails that sit
// in the middle of the page and would be missed by the
// top/bottom 12k text chunks below.
// Cap at 500k characters to prevent runner timeout on
// very large pages.
// ============================================================
const extractEmailsFromText = (text) => {
  const raw = String(text || "");
  const found = [];
  const plain = raw.match(/[a-zA-Z0-9._%+-]+@[a-zA-Z0-9.-]+\.[a-z]{2,}/g) || [];
  found.push(...plain);
  return [...new Set(found.map(e => e.toLowerCase().trim()))].filter(e => e.includes("@"));
};

// CHANGED: html.slice(0, 500000) to prevent runner timeout on large pages
const contact_emails_raw = extractEmailsFromText(html.slice(0, 500000));
// ============================================================

// Extract only the <body> if available
const bodyMatch = html.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
const source = bodyMatch ? bodyMatch[1] : html;

// Extract href links before stripping tags
const hrefs = [...source.matchAll(/href=["']([^"'#]+)["']/gi)]
  .map(m => String(m[1] || "").trim())
  .filter(Boolean);

// Extract + normalize + deduplicate mailto links
const contact_mailtos = [...new Set(
  hrefs
    .filter(h => /^mailto:/i.test(h))
    .map(h =>
      h
        .replace(/^mailto:/i, "")
        .split("?")[0]
        .trim()
        .toLowerCase()
    )
    .filter(Boolean)
)];

// Remove noisy blocks
const cleaned = source
  .replace(/<script[\s\S]*?<\/script>/gi, " ")
  .replace(/<style[\s\S]*?<\/style>/gi, " ")
  .replace(/<noscript[\s\S]*?<\/noscript>/gi, " ")
  .replace(/\s+/g, " ")
  .trim();

// Create top and bottom chunks
const contact_text_top = cleaned.slice(0, 12000);
const contact_text_bottom = cleaned.slice(-12000);

return {
  json: {
    contact_text_top,
    contact_text_bottom,
    contact_links: hrefs,
    contact_mailtos,
    contact_emails_raw, // NEW: full raw HTML email scan added to output
    domain: $node["Parse Router URLs"].json.domain || null,
    canonical_url: $node["Parse Router URLs"].json.canonical_url || null,
    trustpilot_url: $node["Parse Router URLs"].json.trustpilot_url || null,
    contact_url: $node["Parse Router URLs"].json.contact_url || null,
  },
  pairedItem: {
    item: 0,
  },
};

// 1. In the "Done" branch of a Loop, $input.all() contains all items from the loop
const allItems = $input.all(); 
const totalLeads = allItems.length;

// 2. Helper to filter out those image files in the email field
const isValidEmail = (email) => {
  if (!email || typeof email !== 'string') return false;
  const lower = email.toLowerCase();
  return lower.includes('@') && 
         !lower.endsWith('.webp') && 
         !lower.endsWith('.png') && 
         !lower.endsWith('.jpg');
};

// 3. Aggregate stats from your data fields
const highPerformance = allItems.filter(i => (i.json.speed_to_lead_score || 0) >= 8).length;
const lowPerformance = allItems.filter(i => (i.json.speed_to_lead_score || 0) <= 3).length;
const leadsWithEmails = allItems.filter(i => isValidEmail(i.json.email)).length;
const leadsWithSchedulers = allItems.filter(i => i.json.has_scheduler === true).length;

// 4. Create the sample list
const sampleList = allItems
  .slice(0, 5)
  .map(i => `- ${i.json.business_name || 'Unknown'}: Score ${i.json.speed_to_lead_score || 0}`)
  .join('\n');

return {
  emailSubject: `✅ Lead Export: ${totalLeads} Leads (${highPerformance} Hot)`,
  emailBody: `
The SERPER Lead Scraper has finished.

TOTAL STATS:
- Total Leads Processed: ${totalLeads}
- High Quality (Score 8-10): ${highPerformance}
- Critical Gaps (Score 0-3): ${lowPerformance}
- Valid Emails Found: ${leadsWithEmails}
- Schedulers Detected: ${leadsWithSchedulers}

TOP 5 SAMPLES:
${sampleList}

The full list is now available in your Google Sheet.
  `
};
